+        // surgically remove attributes for incident edges before removing node from inner graph
+        if let Some(succs) = self.inner.successors(&canonical) {
+            for v in succs {
+                if let Some(keys) = self.inner.edge_keys(&canonical, v) {
+                    for key in keys {
